-- Prompt 29: encrypted-at-application-boundary integration metadata and idempotent delivery queue.
create table public.integration_connections(id uuid primary key default gen_random_uuid(),gym_id uuid not null references public.gyms(id)on delete cascade,provider_key text not null check(provider_key~'^[a-z][a-z0-9_.-]*$'),provider_category text not null check(provider_category in('membership','check_in','payment','calendar')),status text not null default'disabled'check(status in('disabled','configured','active','error')),encrypted_configuration text,configuration_fingerprint text check(configuration_fingerprint is null or configuration_fingerprint~'^[a-f0-9]{64}$'),key_version smallint not null default 1,last_sync_at timestamptz,last_error_code text,created_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint integration_connections_unique unique(gym_id,provider_key),constraint integration_connections_id_gym_key unique(id,gym_id),constraint integration_config_encrypted check(encrypted_configuration is null or encrypted_configuration like'enc:v%'));
create table public.integration_deliveries(id uuid primary key default gen_random_uuid(),gym_id uuid not null references public.gyms(id)on delete cascade,integration_id uuid not null,provider_key text not null,idempotency_key text not null check(char_length(idempotency_key)between 1 and 255),payload jsonb not null check(jsonb_typeof(payload)='object'),status text not null default'pending'check(status in('pending','processing','processed','retry','dead_letter')),attempts smallint not null default 0,last_error_code text,next_attempt_at timestamptz,processed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint integration_deliveries_connection_fkey foreign key(integration_id,gym_id)references public.integration_connections(id,gym_id)on delete cascade,constraint integration_delivery_unique unique(integration_id,idempotency_key),constraint integration_deliveries_id_gym_key unique(id,gym_id));
create index integration_connections_gym_status_idx on public.integration_connections(gym_id,status,provider_key);create index integration_deliveries_gym_queue_idx on public.integration_deliveries(gym_id,status,next_attempt_at,created_at);
create trigger integration_connections_set_updated_at before update on public.integration_connections for each row execute function public.set_updated_at();create trigger integration_deliveries_set_updated_at before update on public.integration_deliveries for each row execute function public.set_updated_at();
alter table public.integration_connections enable row level security;alter table public.integration_connections force row level security;alter table public.integration_deliveries enable row level security;alter table public.integration_deliveries force row level security;
create policy integration_connections_rpc_only on public.integration_connections for select to authenticated using(false);create policy integration_deliveries_rpc_only on public.integration_deliveries for select to authenticated using(false);
grant all on public.integration_connections,public.integration_deliveries to service_role;revoke all on public.integration_connections,public.integration_deliveries from authenticated,anon;

create or replace function public.get_integration_statuses(target_gym_id uuid)returns table(id uuid,provider_key text,provider_category text,status text,last_sync_at timestamptz,last_error_code text,updated_at timestamptz,queued bigint,dead_letter bigint)language sql stable security definer set search_path=''as $$select connection.id,connection.provider_key,connection.provider_category,connection.status,connection.last_sync_at,connection.last_error_code,connection.updated_at,count(delivery.id)filter(where delivery.status in('pending','retry')),count(delivery.id)filter(where delivery.status='dead_letter')from public.integration_connections connection left join public.integration_deliveries delivery on delivery.integration_id=connection.id and delivery.gym_id=connection.gym_id where connection.gym_id=target_gym_id and private.has_gym_role(target_gym_id,array['owner'])group by connection.id;$$;
create or replace function public.ingest_integration_delivery(target_integration_id uuid,target_provider_key text,event_key text,event_payload jsonb)returns uuid language plpgsql security definer set search_path=''as $$declare selected public.integration_connections;delivery_id uuid;begin if current_setting('request.jwt.claim.role',true)<>'service_role'or char_length(event_key)not between 1 and 255 or jsonb_typeof(event_payload)<>'object'then raise insufficient_privilege;end if;select*into selected from public.integration_connections where id=target_integration_id and provider_key=target_provider_key;if selected.id is null then raise exception'Integration not found';end if;insert into public.integration_deliveries(gym_id,integration_id,provider_key,idempotency_key,payload)values(selected.gym_id,selected.id,selected.provider_key,event_key,event_payload)on conflict(integration_id,idempotency_key)do update set idempotency_key=excluded.idempotency_key returning id into delivery_id;insert into public.audit_logs(gym_id,actor_type,action,target_type,target_id,metadata)values(selected.gym_id,'system','integration.webhook.received','integration_delivery',delivery_id,jsonb_build_object('provider',selected.provider_key,'duplicate',exists(select 1 from public.integration_deliveries where id=delivery_id and created_at<now()-interval'1 second')));return delivery_id;end$$;
create or replace function public.record_integration_delivery_attempt(target_delivery_id uuid,succeeded boolean,error_code text default null)returns text language plpgsql security definer set search_path=''as $$declare selected public.integration_deliveries;next_status text;begin if current_setting('request.jwt.claim.role',true)<>'service_role'then raise insufficient_privilege;end if;select*into selected from public.integration_deliveries where id=target_delivery_id for update;if selected.id is null then raise exception'Delivery not found';end if;next_status:=case when succeeded then'processed'when selected.attempts+1>=5 then'dead_letter'else'retry'end;update public.integration_deliveries set attempts=attempts+1,status=next_status,last_error_code=case when succeeded then null else left(coalesce(error_code,'provider_error'),120)end,processed_at=case when succeeded then now()else null end,next_attempt_at=case when next_status='retry'then now()+make_interval(secs=>least(3600,power(2,selected.attempts+1)::integer*30))else null end where id=selected.id;update public.integration_connections set last_sync_at=case when succeeded then now()else last_sync_at end,last_error_code=case when succeeded then null else left(coalesce(error_code,'provider_error'),120)end,status=case when next_status='dead_letter'then'error'else status end where id=selected.integration_id;return next_status;end$$;
revoke all on function public.get_integration_statuses(uuid),public.ingest_integration_delivery(uuid,text,text,jsonb),public.record_integration_delivery_attempt(uuid,boolean,text)from public,anon;
grant execute on function public.get_integration_statuses(uuid)to authenticated;grant execute on function public.ingest_integration_delivery(uuid,text,text,jsonb),public.record_integration_delivery_attempt(uuid,boolean,text)to service_role;
